import{_ as o,o as s,c as a,a3 as t}from"./chunks/framework.oxq6d-og.js";const u=JSON.parse('{"title":"Design decisions","description":"","frontmatter":{},"headers":[],"relativePath":"en/architecture/decisions.md","filePath":"en/architecture/decisions.md"}'),r={name:"en/architecture/decisions.md"};function i(c,e,n,d,l,h){return s(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="design-decisions" tabindex="-1">Design decisions <a class="header-anchor" href="#design-decisions" aria-label="Permalink to &quot;Design decisions&quot;">​</a></h1><h2 id="why-accessors" tabindex="-1">Why accessors? <a class="header-anchor" href="#why-accessors" aria-label="Permalink to &quot;Why accessors?&quot;">​</a></h2><p>Making every <code>Struct</code> or <code>CFunction</code> choose local and remote APIs leaks transport details into higher layers. Accessors keep those details below a reusable common interface.</p><h2 id="why-system-stubs" tabindex="-1">Why system stubs? <a class="header-anchor" href="#why-system-stubs" aria-label="Permalink to &quot;Why system stubs?&quot;">​</a></h2><p>For redirection, NThread finds small instruction sequences in loaded system modules: <code>EB FE</code>, <code>push reg; ret</code>, <code>jmp reg</code>, <code>ret</code>, and <code>add rsp, 0x28; ret</code>. This avoids placing one large fixed execution payload just to redirect a thread. It does not mean the whole system is allocation-free: accessor middleware and stack-argument cleanup can still allocate target memory.</p><h2 id="why-two-hook-models" tabindex="-1">Why two hook models? <a class="header-anchor" href="#why-two-hook-models" aria-label="Permalink to &quot;Why two hook models?&quot;">​</a></h2><p>NHook patches two bytes with <code>EB FE</code>, parks entering threads, and lets the host process a hit. MinHook uses a five-byte relative jump and a relocated trampoline. The former depends on hit lifecycle and instruction simulation; the latter depends on relocation, near allocation, and a usable detour. Neither is a universal replacement for the other.</p>',7)])])}const p=o(r,[["render",i]]);export{u as __pageData,p as default};
